import { useEffect, useRef } from "react";
import { firstFormError, toastFirstFormError } from "@/lib/form-errors";

export function useErrorToast(errors: unknown): void {
    const previousMessage = useRef<string | undefined>(undefined);
    const message = firstFormError(errors);

    useEffect(() => {
        if (!message) {
            previousMessage.current = undefined;

            return;
        }

        if (message === previousMessage.current) {
            return;
        }

        previousMessage.current = message;
        toastFirstFormError(message);
    }, [message]);
}
